function solve(weight: number[]): number {
    let maxWeight = 0;
    let currentMax = 0;
    let count = 0;
    let i = 0;
    let n = weight.length;

    while (i < n) {
        currentMax = 0;
        let j = i;
        while (j < n && weight[j] < currentMax) {
            currentMax = Math.max(currentMax, weight[j]);
            j++;
        }
        if (j > i && weight[j - 1] < currentMax) {
            count++;
            i = j;
        } else {
            i++;
        }
    }

    return count;
}

